const ANILIST_ENDPOINT = "https://graphql.anilist.co";
const ANILIST_AUTH_ENDPOINT = "https://anilist.co/api/v2/oauth";
const JIKAN_BASE = "https://api.jikan.moe/v4";
const ANISKIP_BASE = "https://api.aniskip.com/v2";

const GENRE_NAME_TO_ID: Record<string, number> = {
  Action: 1, Adventure: 2, Comedy: 4, Drama: 8, Fantasy: 10,
  Horror: 14, Mystery: 7, Romance: 22, "Sci-Fi": 24,
  "Slice of Life": 36, Sports: 30, Supernatural: 37, Thriller: 41,
  Ecchi: 9, Hentai: 12, Mecha: 18, Music: 19, "Psychological": 40,
  School: 23, "Seinen": 42, "Shoujo": 25, "Shounen": 27, "Space": 29,
};

const GENRE_ID_TO_NAME: Record<string, string> = Object.fromEntries(
  Object.entries(GENRE_NAME_TO_ID).map(([name, id]) => [id.toString(), name]),
);

const FORMAT_MAP: Record<string, string> = {
  TV: "TV", MOVIE: "Movie", OVA: "OVA", ONA: "ONA", SPECIAL: "Special",
  TV_SHORT: "TV",
};

const STATUS_MAP: Record<string, string> = {
  FINISHED: "Completed", RELEASING: "Airing", NOT_YET_RELEASED: "Upcoming",
  CANCELLED: "Completed", HIATUS: "Upcoming",
};

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "GET, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type, Authorization",
};

const cache = new Map<string, { data: unknown; expires: number }>();

function getCached(key: string): unknown | null {
  const entry = cache.get(key);
  if (entry && entry.expires > Date.now()) return entry.data;
  if (entry) cache.delete(key);
  return null;
}

function setCache(key: string, data: unknown, ttlMs: number) {
  cache.set(key, { data, expires: Date.now() + ttlMs });
  if (cache.size > 500) {
    const oldest = cache.keys().next().value;
    if (oldest) cache.delete(oldest);
  }
}

async function anilistQuery(query: string, variables: Record<string, unknown>, token?: string, clientId?: string): Promise<unknown> {
  const cacheKey = `anilist:${query}:${JSON.stringify(variables)}`;
  const cached = getCached(cacheKey);
  if (cached) return cached;

  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    "Accept": "application/json",
  };
  if (clientId) headers["X-Client-ID"] = clientId;
  if (token) headers["Authorization"] = `Bearer ${token}`;

  const res = await fetch(ANILIST_ENDPOINT, {
    method: "POST",
    headers,
    body: JSON.stringify({ query, variables }),
  });

  if (!res.ok) {
    throw new Error(`AniList API error: ${res.status}`);
  }

  const json = await res.json() as { data?: unknown; errors?: Array<{ message: string }> };
  if (json.errors) {
    throw new Error(json.errors[0]?.message || "AniList error");
  }

  setCache(cacheKey, json.data, 300000);
  return json.data;
}

async function jikanFetch(path: string): Promise<Response> {
  const cacheKey = `jikan:${path}`;
  const cached = getCached(cacheKey);
  if (cached) return Response.json(cached, { headers: corsHeaders });

  const res = await fetch(`${JIKAN_BASE}${path}`);
  if (!res.ok) {
    return Response.json(
      { error: true, code: res.status === 429 ? "RATE_LIMITED" : "SERVER_ERROR", message: `Jikan API error: ${res.status}`, retry: res.status !== 404 },
      { status: res.status, headers: corsHeaders }
    );
  }
  const data = await res.json();
  setCache(cacheKey, data, 300000);
  return Response.json(data, { headers: corsHeaders });
}

function pad(n: number): string { return n.toString().padStart(2, "0"); }

function formatDate(d: { year: number | null; month: number | null; day: number | null } | null): string | null {
  if (!d || !d.year) return null;
  if (d.month && d.day) return `${d.year}-${pad(d.month)}-${pad(d.day)}`;
  if (d.month) return `${d.year}-${pad(d.month)}-01`;
  return `${d.year}-01-01`;
}

function formatDateString(d: { year: number | null; month: number | null; day: number | null } | null): string {
  if (!d || !d.year) return "?";
  const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  const m = d.month ? months[d.month - 1] : "?";
  const day = d.day ? d.day : "?";
  return `${m} ${day}, ${d.year}`;
}

function stripHtml(str: string | null): string | null {
  if (!str) return null;
  return str.replace(/<[^>]*>/g, "").replace(/\\n/g, "\n").trim();
}

function asDate(val: unknown): { year: number | null; month: number | null; day: number | null } | null {
  if (!val || typeof val !== "object") return null;
  const r = val as Record<string, unknown>;
  return { year: (r.year as number) ?? null, month: (r.month as number) ?? null, day: (r.day as number) ?? null };
}

function normalizeMedia(media: Record<string, unknown>): Record<string, unknown> {
  const title = media.title as Record<string, string | null> | null;
  const coverImage = media.coverImage as Record<string, string | null> | null;
  const startDate = asDate(media.startDate);
  const endDate = asDate(media.endDate);
  const studios = media.studios as Record<string, unknown> | null;
  const genres = media.genres as string[] | null;
  const tags = media.tags as { name: string }[] | null;
  const trailer = media.trailer as Record<string, string | null> | null;
  const relations = media.relations as Record<string, unknown> | null;
  const recommendations = media.recommendations as Record<string, unknown> | null;
  const nextAiringEpisode = media.nextAiringEpisode as Record<string, unknown> | null;
  const characters = media.characters as Record<string, unknown> | null;
  const format = media.format as string | null;
  const episodes = media.episodes as number | null;
  const duration = media.duration as number | null;
  const averageScore = media.averageScore as number | null;
  const popularity = media.popularity as number | null;
  const favourites = media.favourites as number | null;
  const source = media.source as string | null;
  const idMal = media.idMal as number | null;
  const id = media.id as number;

  const malId = idMal || id;

  const normalized: Record<string, unknown> = {
    mal_id: malId,
    anilist_id: id,
    title: title?.english || title?.romaji || "Unknown",
    title_english: title?.english || null,
    title_japanese: title?.native || null,
    images: {
      jpg: { image_url: coverImage?.large || null, large_image_url: coverImage?.extraLarge || coverImage?.large || null },
      webp: { image_url: coverImage?.large || null, large_image_url: coverImage?.extraLarge || coverImage?.large || null },
    },
    type: format ? (FORMAT_MAP[format] || format) : null,
    episodes,
    status: nextAiringEpisode ? "Airing" : (media.status ? STATUS_MAP[media.status as string] || (media.status as string) : null),
    score: averageScore ? Math.round((averageScore / 10) * 10) / 10 : null,
    scored_by: media.meanScore as number || null,
    rank: null,
    popularity,
    members: null,
    favourites: favourites || null,
    synopsis: stripHtml(media.description as string | null),
    season: media.season ? (media.season as string).charAt(0) + (media.season as string).slice(1).toLowerCase() : null,
    year: media.seasonYear as number | null,
    aired: {
      from: formatDate(startDate),
      to: formatDate(endDate),
      string: `${formatDateString(startDate)} to ${endDate?.year ? formatDateString(endDate) : "?"}`,
    },
    broadcast: null,
    studios: studios ? ((studios.nodes as Array<{ name: string }> | null)?.map((s, i) => ({ mal_id: i + 1, name: s.name })) || []) : [],
    genres: genres?.map((g) => ({ mal_id: GENRE_NAME_TO_ID[g] || g.length, name: g })) || [],
    themes: tags?.slice(0, 5).map((t, i) => ({ mal_id: i + 1, name: t.name })) || [],
    source: source ? source.replace(/_/g, " ") : null,
    rating: null,
    duration: duration ? `${duration} min per ep` : null,
    trailer: trailer?.site === "youtube" ? { youtube_id: trailer.id, url: trailer.id ? `https://www.youtube.com/watch?v=${trailer.id}` : null } : null,
    relations: relations ? ((relations.edges as Array<{ relationType: string; node: Record<string, unknown> }> | null)?.map((e) => {
      const n = e.node;
      const nt = n.title as Record<string, string | null> | null;
      return {
        relation: e.relationType?.toLowerCase() || "",
        entry: [{ mal_id: (n.idMal as number) || (n.id as number), name: nt?.english || nt?.romaji || "Unknown", type: FORMAT_MAP[n.format as string] || (n.format as string) || "unknown" }],
      };
    }) || []) : [],
  };

  if (characters) {
    const edges = characters.edges as Array<{ role: string; node: Record<string, unknown>; voiceActors: Array<Record<string, unknown>> }> | null;
    normalized.characters = edges?.map((e) => {
      const cn = e.node;
      const cName = cn.name as Record<string, string>;
      const cImage = cn.image as Record<string, string | null>;
      return {
        mal_id: cn.id as number,
        anilist_id: cn.id as number,
        name: cName?.full || "Unknown",
        images: { jpg: { image_url: cImage?.large || null } },
        role: e.role === "MAIN" ? "Main" : "Supporting",
        voice_actors: e.voiceActors?.map((va) => {
          const vaName = va.name as Record<string, string>;
          const vaImage = va.image as Record<string, string | null>;
          return {
            person: { mal_id: va.id as number, name: vaName?.full || "Unknown", images: { jpg: { image_url: vaImage?.large || null } } },
            language: (va.language as string) || "Japanese",
          };
        }) || [],
      };
    }) || [];
  }

  if (recommendations) {
    const recEdges = recommendations.edges as Array<{ node: Record<string, unknown> }> | null;
    normalized.recommendations = recEdges?.map((e) => {
      const rec = e.node.mediaRecommendation as Record<string, unknown> || e.node;
      const rt = rec.title as Record<string, string | null> | null;
      const rc = rec.coverImage as Record<string, string | null> | null;
      return {
        entry: {
          mal_id: (rec.idMal as number) || (rec.id as number),
          title: rt?.english || rt?.romaji || "Unknown",
          images: { jpg: { image_url: rc?.large || null } },
          type: FORMAT_MAP[rec.format as string] || (rec.format as string) || null,
          score: rec.averageScore ? Math.round(((rec.averageScore as number) / 10) * 10) / 10 : null,
        },
      };
    }) || [];
  }

  return normalized;
}

function getSeasonDates() {
  const now = new Date();
  const m = now.getMonth() + 1;
  const y = now.getFullYear();
  if (m >= 1 && m <= 3) return { current: "WINTER", year: y, next: "SPRING", nextYear: y };
  if (m >= 4 && m <= 6) return { current: "SPRING", year: y, next: "SUMMER", nextYear: y };
  if (m >= 7 && m <= 9) return { current: "SUMMER", year: y, next: "FALL", nextYear: y };
  return { current: "FALL", year: y, next: "WINTER", nextYear: y + 1 };
}

function getAniListSeason(season: string): string {
  const map: Record<string, string> = { winter: "WINTER", spring: "SPRING", summer: "SUMMER", fall: "FALL" };
  return map[season.toLowerCase()] || "WINTER";
}

const MEDIA_FRAGMENT = `
  id
  idMal
  title { romaji english native }
  coverImage { large extraLarge }
  bannerImage
  description
  season
  seasonYear
  format
  status
  episodes
  duration
  averageScore
  meanScore
  popularity
  favourites
  genres
  tags { name }
  source
  studios { nodes { name } }
  startDate { year month day }
  endDate { year month day }
  nextAiringEpisode { episode airingAt }
  relations {
    edges {
      relationType
      node { id idMal title { romaji english } format }
    }
  }
  trailer { id site thumbnail }
`.trim();

export default {
  async fetch(request: Request, env: Record<string, string>): Promise<Response> {
    if (request.method === "OPTIONS") {
      return new Response(null, { status: 200, headers: corsHeaders });
    }

    const url = new URL(request.url);
    const path = url.pathname;
    const clientId = env.ANILIST_CLIENT_ID || "43709";

    try {
      if (path === "/health") {
        return Response.json({ status: "ok", timestamp: new Date().toISOString() }, { headers: corsHeaders });
      }

      if (path === "/anime/trending") {
        const query = `query { Page(perPage: 20) { media(sort: TRENDING_DESC, type: ANIME) { ${MEDIA_FRAGMENT} } } }`;
        const data = await anilistQuery(query, {}, undefined, clientId) as Record<string, unknown>;
        const page = data as { Page: { media: Record<string, unknown>[] } };
        const normalized = page.Page.media.map(normalizeMedia);
        return Response.json({ data: normalized }, { headers: corsHeaders });
      }

      if (path === "/anime/seasonal") {
        const { current, year } = getSeasonDates();
        const query = `query($season: MediaSeason, $year: Int) { Page(perPage: 24) { media(season: $season, seasonYear: $year, type: ANIME, sort: POPULARITY_DESC) { ${MEDIA_FRAGMENT} } } }`;
        const data = await anilistQuery(query, { season: current, year }, undefined, clientId) as Record<string, unknown>;
        const page = data as { Page: { media: Record<string, unknown>[] } };
        const normalized = page.Page.media.map(normalizeMedia);
        return Response.json({ data: normalized }, { headers: corsHeaders });
      }

      if (path === "/anime/upcoming") {
        const { next, nextYear } = getSeasonDates();
        const query = `query($season: MediaSeason, $year: Int) { Page(perPage: 12) { media(season: $season, seasonYear: $year, type: ANIME, sort: POPULARITY_DESC) { ${MEDIA_FRAGMENT} } } }`;
        const data = await anilistQuery(query, { season: next, year: nextYear }, undefined, clientId) as Record<string, unknown>;
        const page = data as { Page: { media: Record<string, unknown>[] } };
        const normalized = page.Page.media.map(normalizeMedia);
        return Response.json({ data: normalized }, { headers: corsHeaders });
      }

      if (path === "/anime/top") {
        const query = `query { Page(perPage: 10) { media(sort: SCORE_DESC, type: ANIME) { ${MEDIA_FRAGMENT} } } }`;
        const data = await anilistQuery(query, {}, undefined, clientId) as Record<string, unknown>;
        const page = data as { Page: { media: Record<string, unknown>[] } };
        const normalized = page.Page.media.map(normalizeMedia);
        return Response.json({ data: normalized }, { headers: corsHeaders });
      }

      const animeDetailMatch = path.match(/^\/anime\/(\d+)$/);
      if (animeDetailMatch) {
        const id = parseInt(animeDetailMatch[1]);
        const cacheKey = `anime-detail:${id}`;
        const cached = getCached(cacheKey);
        if (cached) return Response.json(cached, { headers: corsHeaders });

        const query = `
          query($idMal: Int, $id: Int) {
            Media(idMal: $idMal, id: $id, type: ANIME) {
              ${MEDIA_FRAGMENT}
              characters(page: 1, perPage: 20) {
                edges {
                  role
                  node { id name { full } image { large } }
                  voiceActors { id name { full } image { large } language }
                }
              }
              recommendations(page: 1, perPage: 10) {
                edges {
                  node {
                    mediaRecommendation { id idMal title { romaji english } coverImage { large } format averageScore }
                  }
                }
              }
            }
          }`;

        let data: Record<string, unknown>;
        try {
          data = (await anilistQuery(query, { idMal: id, id: undefined }, undefined, clientId)) as Record<string, unknown>;
        } catch {
          data = (await anilistQuery(query, { idMal: undefined, id }, undefined, clientId)) as Record<string, unknown>;
        }

        if (!data || !data.Media) {
          return Response.json(
            { error: true, code: "NOT_FOUND", message: "Anime not found", retry: false },
            { status: 404, headers: corsHeaders }
          );
        }

        const media = data.Media as Record<string, unknown>;
        const normalized = normalizeMedia(media);
        setCache(cacheKey, normalized, 600000);
        return Response.json(normalized, { headers: corsHeaders });
      }

      const episodesMatch = path.match(/^\/anime\/(\d+)\/episodes$/);
      if (episodesMatch) {
        const id = episodesMatch[1];
        const res = await jikanFetch(`/anime/${id}/episodes`);
        const json = await res.json();
        if (json.data) {
          json.data = json.data.map((ep: Record<string, unknown>) => ({
            ...ep,
            episode: ep.mal_id ?? ep.episode,
          }));
        }
        return Response.json(json, { headers: corsHeaders });
      }

      const skipTimesMatch = path.match(/^\/anime\/(\d+)\/episodes\/(\d+)\/skiptimes$/);
      if (skipTimesMatch) {
        const malId = skipTimesMatch[1];
        const epNum = skipTimesMatch[2];
        const cacheKey = `skiptimes:${malId}:${epNum}`;
        const cached = getCached(cacheKey);
        if (cached) return Response.json(cached, { headers: corsHeaders });

        const res = await fetch(`${ANISKIP_BASE}/skip-times/${malId}/${epNum}?types=op&types=ed`);
        const data = res.ok ? await res.json() : [];
        setCache(cacheKey, data, 3600000);
        return Response.json(data, { headers: corsHeaders });
      }

      const recommendationsMatch = path.match(/^\/anime\/(\d+)\/recommendations$/);
      if (recommendationsMatch) {
        const id = parseInt(recommendationsMatch[1]);
        const query = `
          query($idMal: Int, $id: Int) {
            Media(idMal: $idMal, id: $id, type: ANIME) {
              recommendations(page: 1, perPage: 10) {
                edges {
                  node {
                    mediaRecommendation { id idMal title { romaji english } coverImage { large } format averageScore }
                  }
                }
              }
            }
          }`;

        let data: Record<string, unknown>;
        try {
          data = (await anilistQuery(query, { idMal: id, id: undefined }, undefined, clientId)) as Record<string, unknown>;
        } catch {
          data = (await anilistQuery(query, { idMal: undefined, id }, undefined, clientId)) as Record<string, unknown>;
        }

        if (!data?.Media) {
          return Response.json({ data: [] }, { headers: corsHeaders });
        }

        const recs = (data.Media as Record<string, unknown>).recommendations as Record<string, unknown>;
        const edges = recs?.edges as Array<Record<string, unknown>> | null;
        const recommended = edges
          ?.map((e) => {
            const rec = (e.node as Record<string, unknown>)?.mediaRecommendation as Record<string, unknown>;
            if (!rec) return null;
            const rt = rec.title as Record<string, string | null> | null;
            const rc = rec.coverImage as Record<string, string | null> | null;
            const entryMalId = (rec.idMal as number) || (rec.id as number);
            const entryTitle = rt?.english || rt?.romaji || "Unknown";
            return {
              entry: {
                mal_id: entryMalId,
                anilist_id: rec.id as number,
                title: entryTitle,
                title_english: rt?.english || null,
                title_japanese: rt?.romaji || null,
                images: { jpg: { image_url: rc?.large || null, large_image_url: rc?.large || null }, webp: { image_url: rc?.large || null, large_image_url: rc?.large || null } },
                type: rec.format ? (FORMAT_MAP[rec.format as string] || (rec.format as string)) : null,
                episodes: null, status: null,
                score: rec.averageScore ? Math.round(((rec.averageScore as number) / 10) * 10) / 10 : null,
                scored_by: null, rank: null, popularity: null, members: null, favorites: null, synopsis: null,
                season: null, year: null, aired: { from: null, to: null, string: "?" }, broadcast: null,
                studios: [], genres: [], themes: [], source: null, rating: null, duration: null, trailer: null, relations: [],
              },
            };
          })
          .filter(Boolean) || [];

        return Response.json({ data: recommended }, { headers: corsHeaders });
      }

      if (path === "/search") {
        const q = url.searchParams.get("q") || "";
        const page = parseInt(url.searchParams.get("page") || "1");
        const limit = parseInt(url.searchParams.get("limit") || "25");
        const query = `
          query($q: String, $page: Int, $perPage: Int) {
            Page(page: $page, perPage: $perPage) {
              pageInfo { currentPage hasNextPage lastPage perPage total }
              media(search: $q, type: ANIME) { ${MEDIA_FRAGMENT} }
            }
          }`;
        const data = await anilistQuery(query, { q, page, perPage: limit }, undefined, clientId) as Record<string, unknown>;
        const d = data as { Page: { pageInfo: Record<string, unknown>; media: Record<string, unknown>[] } };
        const pageInfo = d.Page.pageInfo;
        return Response.json({
          data: d.Page.media.map(normalizeMedia),
          pagination: {
            last_visible_page: pageInfo.lastPage || 1,
            has_next_page: pageInfo.hasNextPage || false,
            current_page: pageInfo.currentPage || 1,
            items: { count: d.Page.media.length, total: pageInfo.total || 0, per_page: pageInfo.perPage || limit },
          },
        }, { headers: corsHeaders });
      }

      if (path === "/browse") {
        const params = url.searchParams;
        const page = parseInt(params.get("page") || "1");
        const limit = parseInt(params.get("limit") || "25");
        const variables: Record<string, unknown> = { page, perPage: limit, type: "ANIME" };

        const type = params.get("type");
        if (type) variables.format_in = [type === "Movie" ? "MOVIE" : type === "TV" ? "TV" : type === "OVA" ? "OVA" : type === "ONA" ? "ONA" : type === "Special" ? "SPECIAL" : type];

        const status = params.get("status");
        if (status) {
          const sMap: Record<string, string> = { airing: "RELEASING", completed: "FINISHED", upcoming: "NOT_YET_RELEASED" };
          variables.status = sMap[status.toLowerCase()] || status;
        }

        const genres = params.get("genres");
        if (genres) {
          const genreNames = genres.split(",").filter(Boolean).map((id) => GENRE_ID_TO_NAME[id]).filter(Boolean);
          if (genreNames.length > 0) variables.genre_in = genreNames;
        }

        const score = params.get("score");
        if (score) variables.averageScore_greater = parseInt(score) * 10;

        const sort = params.get("sort");
        if (sort) {
          const sortMap: Record<string, string> = { popularity: "POPULARITY_DESC", score: "SCORE_DESC", start_date: "START_DATE_DESC", title: "TITLE_ROMAJI" };
          variables.sort = [sortMap[sort.toLowerCase()] || "POPULARITY_DESC"];
        } else {
          variables.sort = ["POPULARITY_DESC"];
        }

        const season = params.get("season");
        if (season) variables.season = getAniListSeason(season);

        const year = params.get("year");
        if (year) variables.seasonYear = parseInt(year);

        const query = `
          query($page: Int, $perPage: Int, $type: MediaType, $format_in: [MediaFormat], $status: MediaStatus, $genre_in: [String], $averageScore_greater: Int, $sort: [MediaSort], $season: MediaSeason, $seasonYear: Int) {
            Page(page: $page, perPage: $perPage) {
              pageInfo { currentPage hasNextPage lastPage perPage total }
              media(format_in: $format_in, status: $status, genre_in: $genre_in, averageScore_greater: $averageScore_greater, sort: $sort, season: $season, seasonYear: $seasonYear, type: $type) { ${MEDIA_FRAGMENT} }
            }
          }`;

        const data = await anilistQuery(query, variables, undefined, clientId) as Record<string, unknown>;
        const d = data as { Page: { pageInfo: Record<string, unknown>; media: Record<string, unknown>[] } };
        const pageInfo = d.Page.pageInfo;
        return Response.json({
          data: d.Page.media.map(normalizeMedia),
          pagination: {
            last_visible_page: pageInfo.lastPage || 1,
            has_next_page: pageInfo.hasNextPage || false,
            current_page: pageInfo.currentPage || 1,
            items: { count: d.Page.media.length, total: pageInfo.total || 0, per_page: pageInfo.perPage || limit },
          },
        }, { headers: corsHeaders });
      }

      if (path.startsWith("/schedule/")) {
        const day = path.replace("/schedule/", "");
        return await jikanFetch(`/schedules?filter=${day}&limit=25`);
      }

      if (path === "/genres") {
        const cached = getCached("genres:anilist");
        if (cached) return Response.json(cached, { headers: corsHeaders });

        const query = `query { GenreCollection }`;
        const data = await anilistQuery(query, {}, undefined, clientId) as Record<string, unknown>;
        const d = data as { GenreCollection: string[] };
        const genresData = {
          data: d.GenreCollection
            .filter((g: string) => GENRE_NAME_TO_ID[g])
            .map((g: string) => ({ mal_id: GENRE_NAME_TO_ID[g], name: g, count: 0 })),
        };

        setCache("genres:anilist", genresData, 86400000);
        return Response.json(genresData, { headers: corsHeaders });
      }

      if (path === "/auth/anilist/login") {
        const state = crypto.randomUUID();
        const params = new URLSearchParams({
          client_id: clientId,
          redirect_uri: `${url.origin}/auth/anilist/callback`,
          response_type: "code",
          state,
        });
        const authUrl = `https://anilist.co/api/v2/oauth/authorize?${params}`;
        return Response.json({ authUrl, state }, { headers: corsHeaders });
      }

      if (path === "/auth/anilist/callback") {
        const code = url.searchParams.get("code");
        if (!code) {
          return Response.json({ error: true, code: "AUTH_ERROR", message: "No authorization code provided", retry: false }, { status: 400, headers: corsHeaders });
        }

        const tokenRes = await fetch(`${ANILIST_AUTH_ENDPOINT}/token`, {
          method: "POST",
          headers: { "Content-Type": "application/json", "Accept": "application/json" },
          body: JSON.stringify({
            grant_type: "authorization_code",
            client_id: clientId,
            client_secret: env.ANILIST_CLIENT_SECRET || "",
            redirect_uri: `${url.origin}/auth/anilist/callback`,
            code,
          }),
        });

        if (!tokenRes.ok) {
          return Response.json({ error: true, code: "AUTH_ERROR", message: "Failed to exchange authorization code", retry: true }, { status: 400, headers: corsHeaders });
        }

        const tokenData = await tokenRes.json();
        return Response.json(tokenData, { headers: corsHeaders });
      }

      return Response.json({ error: true, code: "NOT_FOUND", message: "Route not found", retry: false }, { status: 404, headers: corsHeaders });
    } catch (err) {
      return Response.json(
        { error: true, code: "SERVER_ERROR", message: err instanceof Error ? err.message : "Internal error", retry: true },
        { status: 500, headers: corsHeaders }
      );
    }
  },
};
